<script setup lang="ts">
import { ref, computed, onMounted } from 'vue'
import { useRouter } from 'vue-router'
import Button from '@/components/common/Button.vue'

const router = useRouter()

interface Playlist {
  id: string
  name: string
  songs: string[]
  songCount: number
  createdAt?: string
}

const playlists = ref<Playlist[]>([])

const favoritesCount = computed(() => {
  const saved = localStorage.getItem('favorites')
  return saved ? JSON.parse(saved).length : 0
})

const recentCount = computed(() => {
  const saved = localStorage.getItem('recent')
  return saved ? JSON.parse(saved).length : 0
})

function handleCreatePlaylist() {
  const name = prompt('请输入歌单名称：')
  if (!name) return
  
  const newPlaylist: Playlist = {
    id: `playlist-${Date.now()}`,
    name,
    songs: [],
    songCount: 0,
    createdAt: new Date().toISOString()
  }
  
  const saved = localStorage.getItem('playlists')
  const playlistList = saved ? JSON.parse(saved) : []
  playlistList.push(newPlaylist)
  localStorage.setItem('playlists', JSON.stringify(playlistList))
  
  playlists.value = playlistList
  router.push(`/playlist/${newPlaylist.id}`)
}

onMounted(() => {
  const saved = localStorage.getItem('playlists')
  if (saved) {
    playlists.value = JSON.parse(saved)
  }
})
</script>

